// Default = whole Brevo account (all lists). Pass body.list_id to scope to one list.
const body=($('Webhook').first().json.body)||{};
const listId=(body.list_id!=null)?Number(body.list_id):null;
const path=(listId!=null)?('/v3/contacts/lists/'+listId+'/contacts'):'/v3/contacts';
return [{json:{path, listId}}];

const cnt = ((($('Count').first()||{}).json)||{}).count || 0;
const path = ((($('Resolve').first()||{}).json)||{}).path || '/v3/contacts';
const pages = Math.ceil(cnt/1000);
const out=[]; for(let i=0;i<pages;i++){ out.push({json:{path, offset:i*1000}}); }
// --- job_runs: open the run ---
const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,''); const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const sd=$getWorkflowStaticData('global'); const now=new Date().toISOString();
let jobId=''; try{ const j=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/job_runs/records',headers:pbH,body:{kind:'brevo-backfill',label:'Import / refresh from Brevo',status:'running',total:cnt,processed:0,started:now},json:true}); jobId=j.id; }catch(e){}
sd.bfJobId=jobId; sd.bfTotal=cnt;
if(!pages && jobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+jobId,headers:pbH,body:{status:'done',finished:now,processed:0,message:'No Brevo contacts'},json:true}); }catch(e){} sd.bfJobId=''; }
return out;

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const pages=$input.all();
const map=new Map();
for(const p of pages){ const cs=(p.json&&p.json.contacts)||[]; for(const c of cs){ if(c&&c.email){ map.set(String(c.email).trim().toLowerCase(), c.emailBlacklisted===true); } } }
const entries=[...map.entries()];
let created=0, updated=0, skipped=0;
const upsert=async([email,bl])=>{
  try{ await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/contacts/records',headers:pbH,body:{email,source_type:'brevo',blocklisted:bl},json:true}); created++; }
  catch(e){
    try{ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter:'email="'+email+'"',perPage:1,fields:'id,blocklisted'},headers:pbH,json:true}); const rec=r.items&&r.items[0]; if(rec){ if(rec.blocklisted!==bl){ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+rec.id,headers:pbH,body:{blocklisted:bl},json:true}); updated++; } } else { skipped++; } }catch(_){ skipped++; }
  }
};
const sd=$getWorkflowStaticData('global');
for(let i=0;i<entries.length;i+=40){ await Promise.all(entries.slice(i,i+40).map(upsert)); if(sd.bfJobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.bfJobId,headers:pbH,body:{processed:Math.min(i+40,entries.length),message:'importing…'},json:true}); }catch(e){} } }
if(sd.bfJobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.bfJobId,headers:pbH,body:{status:'done',finished:new Date().toISOString(),processed:entries.length,total:entries.length,message:'Imported '+created+', updated '+updated},json:true}); }catch(e){} sd.bfJobId=''; }
return [{json:{created,updated,total:entries.length}}];
